# E2e tests for category: smoke
# Generated by html-to-markdown-e2e-generator — do not edit manually.

library(testthat)
library(htmltomarkdown)

test_that("smoke_empty_string: Empty string produces empty output", {
  html <- ""
  result <- convert(html)
  content <- result$content %||% ""

  expect_equal(trimws(content), "")
})

test_that("smoke_simple_heading: H1 heading converts to ATX markdown", {
  html <- "<h1>Title</h1>"
  result <- convert(html)
  content <- result$content %||% ""

  # content_contains_all
  expect_true(grepl("# Title", content, fixed = TRUE))
})

test_that("smoke_simple_paragraph: Simple paragraph converts correctly", {
  html <- "<p>Hello World</p>"
  result <- convert(html)
  content <- result$content %||% ""

  expect_equal(trimws(content), "Hello World")
  expect_true(nchar(trimws(content)) > 0)
})
